using UnityEngine;
using System.Collections;

public class ChimneySmokeController : MonoBehaviour
{
    public ParticleSystem chimneySmoke; // Assign your Particle System in the inspector

    // These values can be adjusted in the inspector or within the script
    [SerializeField] private float minSmokeDuration = 20f; // Minimum duration of smoke
    [SerializeField] private float maxSmokeDuration = 30f; // Maximum duration of smoke
    [SerializeField] private float minWaitDuration = 120f; // Minimum wait duration between smokes
    [SerializeField] private float maxWaitDuration = 180f; // Maximum wait duration between smokes

    // Start is called before the first frame update
    void Start()
    {
        if(chimneySmoke != null)
        {
            StartCoroutine(SmokeRoutine());
        }
        else
        {
            Debug.LogError("ChimneySmokeController: Missing chimney smoke ParticleSystem.", this);
        }
    }

    private IEnumerator SmokeRoutine()
    {
        while (true) // Infinite loop to continuously manage the smoke effect
        {
            // Calculate random durations for the smoke effect and the waiting period
            float smokeDuration = Random.Range(minSmokeDuration, maxSmokeDuration);
            float waitDuration = Random.Range(minWaitDuration, maxWaitDuration);

            // Start the smoke
            chimneySmoke.Play();

            // Log for debugging purposes
            Debug.Log("Chimney smoke started for " + smokeDuration + " seconds.", this);

            // Wait for the smoke duration
            yield return new WaitForSeconds(smokeDuration);

            // Stop the smoke
            chimneySmoke.Stop();

            // Log for debugging purposes
            Debug.Log("Chimney smoke stopped. Waiting for " + waitDuration + " seconds before next smoke.", this);

            // Wait for the designated period before emitting smoke again
            yield return new WaitForSeconds(waitDuration);
        }
    }
}
```

What this script does:

1. **Starts with emitting smoke:** Once you run your scene, the `Start` method kicks off the `SmokeRoutine` coroutine, assuming the `chimneySmoke` Particle System is assigned.

2. **Emitting smoke for a random duration:** The smoke emits for a random duration between `minSmokeDuration` and `maxSmokeDuration` (20 to 30 seconds).

3. **Pausing between smoke emissions:** After emitting, the smoke stops, and the coroutine waits for a random duration between `minWaitDuration` and `maxWaitDuration` (2 to 3 minutes) before starting the cycle over.

4. **Debug logs:** The script logs start and stop actions with durations for debugging and verification purposes.

To use this script:

1. Attach it to a GameObject in your scene (probably the chimney).
2. Make sure you have a Particle System component on the same GameObject or a child of it, representing the smoke.
3. In the Unity Inspector, assign the chimney's Particle System to the `chimneySmoke` field of this script.
4. Adjust the minimum and maximum durations for the smoke and wait periods directly in the Inspector if desired.

